// Set up document styles
document.body.style.fontFamily = "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif";
document.body.style.maxWidth = "800px";
document.body.style.margin = "0 auto";
document.body.style.padding = "20px";
document.body.style.backgroundColor = "#f5f7fa";
document.body.style.color = "#333";

// Main Heading
const h1 = document.createElement("h1");
h1.textContent = "Interactive JavaScript Elements";
h1.style.textAlign = "center";
h1.style.color = "#2c3e50";
h1.style.marginBottom = "40px";
h1.style.borderBottom = "2px solid #3498db";
h1.style.paddingBottom = "10px";
document.body.appendChild(h1);

// Create reusable feature box
function createFeatureBox(title, description) {
  const box = document.createElement("div");
  box.className = "feature-box";
  box.style.backgroundColor = "white";
  box.style.borderRadius = "8px";
  box.style.boxShadow = "0 4px 6px rgba(0, 0, 0, 0.1)";
  box.style.padding = "25px";
  box.style.marginBottom = "30px";
  box.style.transition = "transform 0.2s ease";

  box.addEventListener("mouseover", () => {
    box.style.transform = "translateY(-3px)";
  });
  box.addEventListener("mouseout", () => {
    box.style.transform = "translateY(0)";
  });

  const h2 = document.createElement("h2");
  h2.textContent = title;
  h2.style.color = "#3498db";
  h2.style.marginTop = "0";

  const p = document.createElement("p");
  p.textContent = description;
  p.style.color = "#666";
  p.style.marginBottom = "15px";
  p.style.lineHeight = "1.5";

  box.appendChild(h2);
  box.appendChild(p);

  return box;
}

// Color Changer Feature
const colorBox = createFeatureBox(
  "Color Changing Button",
  "Click the button below to see it change colors dynamically. The button cycles through a series of vibrant colors while maintaining a sleek, modern aesthetic."
);
const colorButton = document.createElement("button");
colorButton.textContent = "Click to Change Color";
colorButton.style.backgroundColor = "#3498db";
colorButton.style.color = "white";
colorButton.style.border = "none";
colorButton.style.padding = "12px 24px";
colorButton.style.borderRadius = "4px";
colorButton.style.cursor = "pointer";
colorButton.style.fontSize = "16px";
colorButton.style.transition = "all 0.3s ease";
colorButton.style.margin = "20px auto";
colorButton.style.display = "block";

const colors = ['#3498db', '#2ecc71', '#e74c3c', '#9b59b6', '#f1c40f', '#1abc9c'];
let colorIndex = 0;
colorButton.addEventListener("click", function () {
  colorIndex = (colorIndex + 1) % colors.length;
  this.style.backgroundColor = colors[colorIndex];
});

colorBox.appendChild(colorButton);
document.body.appendChild(colorBox);

// Greeting Feature
const greetingBox = createFeatureBox(
  "Time-Based Greeting",
  "This button triggers an alert with a customized greeting message based on the current time of day. Whether it's morning, afternoon, evening, or night, you'll get an appropriate greeting."
);
const greetingBtn = document.createElement("button");
greetingBtn.textContent = "Show Time-Based Greeting";
Object.assign(greetingBtn.style, colorButton.style);

greetingBtn.addEventListener("click", function () {
  const hour = new Date().getHours();
  let greeting;
  if (hour < 12) {
    greeting = "Good morning! Rise and shine!";
  } else if (hour < 18) {
    greeting = "Good afternoon! Hope you're having a productive day!";
  } else if (hour < 22) {
    greeting = "Good evening! Time to unwind!";
  } else {
    greeting = "Good night! Don't stay up too late!";
  }
  alert(greeting + "\n\nThe current time is: " + new Date().toLocaleTimeString());
});

greetingBox.appendChild(greetingBtn);
document.body.appendChild(greetingBox);

// Calculator Feature
const calcBox = createFeatureBox(
  "Basic Calculator",
  "Enter two numbers below and click calculate to perform addition. The form includes input validation and displays a clean, readable result."
);
const calcContainer = document.createElement("div");
calcContainer.style.display = "flex";
calcContainer.style.flexDirection = "column";
calcContainer.style.gap = "15px";

const num1 = document.createElement("input");
const num2 = document.createElement("input");
[num1, num2].forEach((input) => {
  input.type = "number";
  input.placeholder = "Enter number";
  input.style.padding = "10px";
  input.style.border = "1px solid #ddd";
  input.style.borderRadius = "4px";
  input.style.fontSize = "16px";
});

const calcBtn = document.createElement("button");
calcBtn.textContent = "Calculate Sum";
Object.assign(calcBtn.style, colorButton.style);

const resultDiv = document.createElement("div");
resultDiv.style.fontWeight = "bold";
resultDiv.style.marginTop = "10px";
resultDiv.style.padding = "10px";
resultDiv.style.backgroundColor = "#f0f8ff";
resultDiv.style.borderRadius = "4px";

calcBtn.addEventListener("click", () => {
  const val1 = parseFloat(num1.value);
  const val2 = parseFloat(num2.value);

  if (isNaN(val1) || isNaN(val2)) {
    resultDiv.textContent = "Please enter valid numbers in both fields";
    resultDiv.style.color = "#e74c3c";
  } else {
    resultDiv.textContent = `Result: ${val1} + ${val2} = ${val1 + val2}`;
    resultDiv.style.color = "#2ecc71";
  }
});

calcContainer.appendChild(num1);
calcContainer.appendChild(num2);
calcContainer.appendChild(calcBtn);
calcContainer.appendChild(resultDiv);
calcBox.appendChild(calcContainer);
document.body.appendChild(calcBox);
